import{_ as a,o as l,c as t,ag as i}from"./chunks/framework.C9sp7nFj.js";const m=JSON.parse('{"title":"系统配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/system-settings.md","filePath":"guide/help/system-settings.md","lastUpdated":1780491682000}'),o={name:"guide/help/system-settings.md"};function r(d,e,p,h,c,s){return l(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="系统配置" tabindex="-1">系统配置 <a class="header-anchor" href="#系统配置" aria-label="Permalink to &quot;系统配置&quot;">​</a></h1><p>系统配置是 PanSave 的基础。配置完成后，频道扫描、监控策略、豆瓣求片和缺集扫描才知道“从哪里找、存到哪里、用哪个媒体库确认结果”。</p><h2 id="网盘配置" tabindex="-1">网盘配置 <a class="header-anchor" href="#网盘配置" aria-label="Permalink to &quot;网盘配置&quot;">​</a></h2><p>入口：<code>系统配置 / 网盘配置</code></p><p>这里添加 123 云盘或 115 网盘账号。添加后还需要进入 <code>资源获取 / 转存策略</code> 配置目录，否则系统只知道账号存在，不知道资源要存到哪里。</p><p>建议做法：</p><ol><li>先添加账号。</li><li>确认账号状态正常。</li><li>到转存策略里添加目录。</li><li>给每个要自动接收资源的网盘选择一个“整理源目录”。</li></ol><p>同一个系统最多维护 10 个网盘账号。超过上限后，运行中的转存流程会被阻断，设置页仍允许你删除或调整配置。</p><h2 id="代理配置" tabindex="-1">代理配置 <a class="header-anchor" href="#代理配置" aria-label="Permalink to &quot;代理配置&quot;">​</a></h2><p>入口：<code>系统配置 / 代理配置</code></p><p>代理只用于 Telegram 和 TMDB。豆瓣、Emby、网盘接口等请求不会复用这里的代理。</p><p>如果你的服务器本身可以直连 Telegram 和 TMDB，可以不配置代理。开启代理时，需要同时填写地址和端口。</p><h2 id="telegram-配置" tabindex="-1">Telegram 配置 <a class="header-anchor" href="#telegram-配置" aria-label="Permalink to &quot;Telegram 配置&quot;">​</a></h2><p>入口：<code>系统配置 / Telegram 配置</code></p><p>这个页面包含三件事：</p><ul><li>Telegram 账号登录</li><li>内置机器人配置</li><li>频道资源池维护</li></ul><h3 id="telegram-账号" tabindex="-1">Telegram 账号 <a class="header-anchor" href="#telegram-账号" aria-label="Permalink to &quot;Telegram 账号&quot;">​</a></h3><p>使用 Telegram API 模式时，需要填写 <code>API ID</code>、<code>API Hash</code> 和手机号，再按页面提示完成验证码登录。</p><p>修改 <code>API ID</code>、<code>API Hash</code> 或手机号会重置登录态，这是正常行为。只改代理或重复保存相同配置，不会强制重新登录。</p><h3 id="内置机器人" tabindex="-1">内置机器人 <a class="header-anchor" href="#内置机器人" aria-label="Permalink to &quot;内置机器人&quot;">​</a></h3><p>内置机器人用于：</p><ul><li>给管理员发送系统提醒</li><li>执行机器人转存</li><li>发送部分任务反馈</li></ul><p>机器人需要填写 Bot Token，并绑定系统使用的 Telegram 用户 ID。系统通知会优先通过机器人发给这个用户。</p><h3 id="频道资源池" tabindex="-1">频道资源池 <a class="header-anchor" href="#频道资源池" aria-label="Permalink to &quot;频道资源池&quot;">​</a></h3><p>频道资源池只是“可用频道列表”。加入频道后，并不代表它一定会参与频道扫描或豆瓣求片。</p><p>后续还需要在这些入口单独启用：</p><ul><li><code>频道扫描</code></li><li><code>监控策略</code></li><li><code>频道监控</code></li><li><code>榜单订阅</code></li></ul><p>这样做是为了让同一个频道可以服务不同场景，也避免某个频道被误加入所有自动任务。</p><h2 id="邮箱配置" tabindex="-1">邮箱配置 <a class="header-anchor" href="#邮箱配置" aria-label="Permalink to &quot;邮箱配置&quot;">​</a></h2><p>入口：<code>系统配置 / 邮箱配置</code></p><p>邮箱用于发送：</p><ul><li>管理员系统通知</li><li>豆瓣求片用户通知</li><li>任务阻断提醒</li></ul><p>SMTP 地址、端口、发件邮箱需要填写完整。保存前建议先用“测试发送”确认能正常发信。</p><p>免打扰只影响邮件，不影响 Telegram 机器人通知。</p><h2 id="媒体服务配置" tabindex="-1">媒体服务配置 <a class="header-anchor" href="#媒体服务配置" aria-label="Permalink to &quot;媒体服务配置&quot;">​</a></h2><p>入口：<code>系统配置 / 媒体服务配置</code></p><p>这里配置 TMDB 和 Emby。</p><table tabindex="0"><thead><tr><th>配置</th><th>用途</th></tr></thead><tbody><tr><td>TMDB</td><td>确认电影、剧集、年份、海报和标准季集结构。</td></tr><tr><td>Emby</td><td>确认资源是否已入库，是否已经缺集。</td></tr></tbody></table><p>新增或编辑 TMDB、Emby 时，系统会先测试连通性和凭据是否有效，测试失败不会保存。</p><p>Emby 最多允许配置 5 个。多 Emby 场景下，监控策略、榜单订阅、豆瓣求片和缺集扫描都会按当前选中的 Emby 服务器隔离。</p><h2 id="账号和授权" tabindex="-1">账号和授权 <a class="header-anchor" href="#账号和授权" aria-label="Permalink to &quot;账号和授权&quot;">​</a></h2><p>首次登录后建议在右上角“账号设置”里修改默认用户名或密码。</p><p>授权码在“授权设置”页面填写。授权有效时，侧边栏版本号旁会显示“已激活”。详细步骤见 <a href="/guide/help/license">授权码使用</a>。</p><h2 id="删除配置时的保护" tabindex="-1">删除配置时的保护 <a class="header-anchor" href="#删除配置时的保护" aria-label="Permalink to &quot;删除配置时的保护&quot;">​</a></h2><p>网盘账号、内置机器人、Emby、TMDB 等基础配置如果已经被业务使用，删除时会被阻断。</p><p>常见例子：</p><ul><li>网盘账号被频道扫描或监控策略引用</li><li>Emby 被豆瓣求片、榜单订阅或缺集扫描引用</li><li>内置机器人被转存策略引用</li></ul><p>遇到阻断时，按弹窗提示先去对应功能解除引用或更换配置，再回来删除。系统不会为了删除基础配置而偷偷清理业务数据。</p>',48)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
